function calcItem(f) {
  const qty=parseFloat(f.qty)||0, price=parseFloat(f.price)||0;
  const fac=f.useCustom?(parseFloat(f.equiv)||1):1;
  const importeTotal=r2(qty*price);
  const cantStd=r2(qty*fac), priceStd=fac>0?r2(price/fac):price;
  const unitStd=f.useCustom?f.stdUnit:f.unit;
  const iva=f.iva;
  const sinIVA=iva===0?importeTotal:r2(importeTotal/(1+iva));
  return {cantStd,priceStd,unitStd,importeTotal,sinIVA,impuestos:r2(importeTotal-sinIVA)};
}
