// ItemFields — outside App so React never remounts it
// ═══════════════════════════════════════════════════════
function ItemFields({f, chgFn, setFn, e, cats, als, catalogo, onCatalogSelect}) {
  const [showAc,setShowAc] = useState(false);
  const acRef = useRef(null);
  const comp  = (f.qty&&f.price) ? calcItem(f) : null;

  const acItems = useMemo(()=>{
    if(!catalogo||!f.prod||f.prod.length<1) return [];
    return catalogo
      .map(item=>({item,score:fuzzyScore(f.prod,item.nombre)}))
      .filter(({score})=>score>0)
      .sort((a,b)=>b.score-a.score)
      .slice(0,8)
      .map(({item})=>item);
  },[catalogo,f.prod]);

  useEffect(()=>{
    if(!showAc) return;
    const handle=(e)=>{ if(acRef.current&&!acRef.current.contains(e.target)) setShowAc(false); };
    document.addEventListener("mousedown",handle);
    return ()=>document.removeEventListener("mousedown",handle);
  },[showAc]);

  const handleProdChange = (e2) => { chgFn("prod")(e2); setShowAc(true); };

  const selectItem = (item) => {
    onCatalogSelect && onCatalogSelect(item);
    setShowAc(false);
  };

  return (
    <div>
      <div style={{marginBottom:"14px"}}>
        <label style={sLbl("8px")}>Categoría</label>
        <div style={{display:"flex",gap:"6px",flexWrap:"wrap"}}>
          {cats.map(c=>(
            <button key={c} onClick={()=>setFn("cat",c)}
              style={sPill(f.cat===c,alClr(f.al||als[0]),{fontSize:"12px",padding:"6px 12px"})}>
              {c}
            </button>
          ))}
        </div>
      </div>

      <div style={{marginBottom:"14px"}}>
        <label style={sLbl()}>Producto / Insumo *</label>
        <div style={{position:"relative"}} ref={acRef}>
          <input
            type="text"
            value={f.prod}
            onChange={handleProdChange}
            onFocus={()=>f.prod.length>=1&&setShowAc(true)}
            placeholder="Escribe o busca del catálogo..."
            style={sInp(e.prod)}
            autoComplete="off"
          />
          {showAc&&acItems.length>0&&(
            <div style={{position:"absolute",top:"calc(100% + 2px)",left:0,right:0,background:"white",border:"1.5px solid #E0D5C8",borderRadius:"10px",zIndex:50,overflow:"hidden",boxShadow:"0 4px 16px rgba(0,0,0,0.10)"}}>
              {acItems.map(item=>(
                <div
                  key={item.id}
                  onMouseDown={(ev)=>{ev.preventDefault();selectItem(item);}}
                  style={{padding:"10px 14px",cursor:"pointer",borderBottom:"0.5px solid #F0EBE3",display:"flex",justifyContent:"space-between",alignItems:"center",background:"white"}}
                  onMouseEnter={ev=>ev.currentTarget.style.background="#FDF5F0"}
                  onMouseLeave={ev=>ev.currentTarget.style.background="white"}
                >
                  <span style={{fontWeight:"600",color:"#1C1208",fontFamily:"inherit",fontSize:"14px"}}>{item.nombre}</span>
                  <div style={{display:"flex",gap:"4px",flexShrink:0}}>
                    <span style={{fontSize:"11px",background:alClr(item.almacen)+"22",color:alClr(item.almacen),borderRadius:"4px",padding:"2px 6px",fontFamily:"inherit"}}>{item.almacen}</span>
                    <span style={{fontSize:"11px",background:"#F5F0EB",color:"#7A6B5A",borderRadius:"4px",padding:"2px 6px",fontFamily:"inherit"}}>{item.categoria}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        {e.prod&&<span style={ERR_MSG}>Campo requerido</span>}
      </div>

      <div style={{background:"#F8F3EE",borderRadius:"10px",padding:"12px",marginBottom:"14px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"10px"}}>
          <label style={sLbl("0")}>Unidad de compra</label>
          <div style={{display:"flex",alignItems:"center",gap:"8px"}}>
            <span style={{fontSize:"12px",color:f.useCustom?"#C4622D":"#8A7B6A",fontFamily:"inherit"}}>Personalizada</span>
            <div onClick={()=>setFn("useCustom",!f.useCustom)}
              style={{width:"40px",height:"22px",borderRadius:"11px",background:f.useCustom?"#C4622D":"#D0C8BE",position:"relative",cursor:"pointer"}}>
              <div style={{position:"absolute",top:"3px",left:f.useCustom?"21px":"3px",width:"16px",height:"16px",borderRadius:"50%",background:"white",transition:"left 0.2s"}}/>
            </div>
          </div>
        </div>
        {!f.useCustom?(
          <div style={{display:"grid",gridTemplateColumns:"1.5fr 1fr",gap:"10px"}}>
            <div>
              <label style={sLbl()}>Cantidad *</label>
              <input type="number" inputMode="decimal" value={f.qty} onChange={chgFn("qty")} placeholder="0" style={sInp(e.qty)}/>
              {e.qty&&<span style={ERR_MSG}>Requerido</span>}
            </div>
            <div>
              <label style={sLbl()}>Unidad</label>
              <select value={f.unit} onChange={chgFn("unit")} style={sInp(false)}>
                {UNITS.map(u=>(<option key={u}>{u}</option>))}
              </select>
            </div>
          </div>
        ):(
          <div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px",marginBottom:"8px"}}>
              <div>
                <label style={sLbl()}>Nombre unidad *</label>
                <input type="text" value={f.customUnit} onChange={chgFn("customUnit")} placeholder="Ej: Bulto" style={sInp(e.customUnit)}/>
                {e.customUnit&&<span style={ERR_MSG}>Requerido</span>}
              </div>
              <div>
                <label style={sLbl()}>Cantidad *</label>
                <input type="number" inputMode="decimal" value={f.qty} onChange={chgFn("qty")} placeholder="0" style={sInp(e.qty)}/>
                {e.qty&&<span style={ERR_MSG}>Requerido</span>}
              </div>
            </div>
            <label style={sLbl()}>{"1 "+(f.customUnit||"unidad")+" equivale a…"}</label>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px"}}>
              <div>
                <input type="number" inputMode="decimal" value={f.equiv} onChange={chgFn("equiv")} placeholder="20" style={sInp(e.equiv)}/>
                {e.equiv&&<span style={ERR_MSG}>Requerido</span>}
              </div>
              <div>
                <select value={f.stdUnit} onChange={chgFn("stdUnit")} style={sInp(false)}>
                  {UNITS.map(u=>(<option key={u}>{u}</option>))}
                </select>
              </div>
            </div>
            {comp&&comp.cantStd>0&&(
              <div style={{marginTop:"8px",background:"white",borderRadius:"8px",padding:"8px 10px",fontSize:"13px",color:"#5A4A3A",fontFamily:"inherit"}}>
                {"✓ "+f.qty+" "+(f.customUnit||"uds")+" = "}<strong>{comp.cantStd+" "+f.stdUnit}</strong>
              </div>
            )}
          </div>
        )}
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px",marginBottom:"14px"}}>
        <div>
          <label style={sLbl()}>{"Precio por "+(f.useCustom?(f.customUnit||"unidad"):f.unit)+" *"}</label>
          <input type="number" inputMode="decimal" value={f.price} onChange={chgFn("price")} placeholder="0.00" style={sInp(e.price)}/>
          {e.price&&<span style={ERR_MSG}>Requerido</span>}
        </div>
        <div>
          <label style={sLbl()}>IVA</label>
          <select value={f.iva} onChange={ev=>setFn("iva",parseFloat(ev.target.value))} style={sInp(false)}>
            <option value={0.16}>16% con IVA</option>
            <option value={0}>0% sin IVA</option>
          </select>
        </div>
      </div>

      {comp&&comp.importeTotal>0&&(
        <div style={{background:"#1A0A00",borderRadius:"10px",padding:"12px 14px",marginBottom:"14px"}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:"4px"}}>
            <span style={{fontSize:"12px",color:"#A08060",fontFamily:"inherit"}}>Sin IVA</span>
            <span style={{fontSize:"13px",color:"#F5DFC0",fontFamily:"inherit"}}>{fmtMXN(comp.sinIVA)}</span>
          </div>
          {comp.impuestos>0&&(
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:"4px"}}>
              <span style={{fontSize:"12px",color:"#A08060",fontFamily:"inherit"}}>IVA 16%</span>
              <span style={{fontSize:"13px",color:"#F5DFC0",fontFamily:"inherit"}}>{fmtMXN(comp.impuestos)}</span>
            </div>
          )}
          <div style={{display:"flex",justifyContent:"space-between",borderTop:"1px solid #3D2610",paddingTop:"6px",marginTop:"4px"}}>
            <span style={{fontSize:"13px",color:"#A08060",fontWeight:"600",fontFamily:"inherit"}}>Total</span>
            <span style={{fontSize:"18px",color:"#C4622D",fontWeight:"700",fontFamily:"inherit"}}>{fmtMXN(comp.importeTotal)}</span>
          </div>
        </div>
      )}

      <div style={{marginBottom:"16px"}}>
        <label style={sLbl()}>Notas</label>
        <input type="text" value={f.notas} onChange={chgFn("notas")} placeholder="Opcional" style={sInp(false)}/>
      </div>
    </div>
  );
}

