// ListMgr lives outside App so keystrokes never remount it
function ListMgr({list, newVal, onNewVal, onAdd, onRemove}) {
  return (
    <div>
      <div style={{display:"flex",flexWrap:"wrap",gap:"8px",marginBottom:"12px"}}>
        {list.map(a=>(
          <div key={a} style={{display:"flex",alignItems:"center",gap:"4px",background:"#F5F0EB",borderRadius:"20px",padding:"5px 12px"}}>
            <span style={{fontSize:"13px",color:"#5A4A3A",fontFamily:"inherit"}}>{a}</span>
            {list.length>1 && (
              <button onClick={()=>onRemove(a)} style={{background:"none",border:"none",color:"#A08060",cursor:"pointer",fontSize:"16px",lineHeight:1,fontFamily:"inherit"}}>x</button>
            )}
          </div>
        ))}
      </div>
      <div style={{display:"flex",gap:"8px"}}>
        <input
          type="text"
          value={newVal}
          onChange={e=>onNewVal(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&onAdd()}
          placeholder="Nuevo..."
          style={{flex:1,border:"1.5px solid #E0D5C8",borderRadius:"8px",padding:"9px 12px",fontSize:"14px",outline:"none",fontFamily:"inherit"}}
        />
        <button onClick={onAdd} style={{background:"#C4622D",color:"white",border:"none",borderRadius:"8px",padding:"9px 16px",cursor:"pointer",fontWeight:"700",fontSize:"18px",fontFamily:"inherit"}}>+</button>
      </div>
    </div>
  );
}

